    ['Hypnotic Hospitality'] = {
        id = 1049,
        start_npc = 'Green Thumb Moogle',
        start_zone = 'Mog Garden',
        start_pos = nil,
        description = 'A mob of merry moogles has manifested in your Mog Garden. Stockpile the subsequent sundries so your grand guests can be properly pampered: a moat carp creel from the pond as well as a branch of gnatbane and a date from the furrows.',
        reward = 'Hoe',
        fame = 'Other',
        fame_level = nil,
        title = 'Quartet Captivator',
        repeatable = nil,
        previous = {'Trinket for the Tyrant'},
        next = {'Titillating Tomes'},
        requirements = {
            {name = 'Gnatbane', count = 1},
            {name = 'Date', count = 1},
            {name = 'Moat Carp Creel', count = 1},
        },
        walkthrough = '1. Speak with the Green Thumb Moogle for a dialogue, initiating this quest.\n2. Obtain and trade your Green Thumb Moogle a Moat Carp Creel, a Date, and a Gnatbane.\n   - Gnatbane is a slightly rare result of harvesting Herb Seeds or Arborscent Seed in the Garden Furrow. No fertilizer is required.\n   - Date can be harvested as a result of Cactus Stems. No fertilizer is required.\n   - Moat Carp Creel can be obtained from the Pond Dredger. Using a Super Baitball may increase your odds of obtaining this.\n     - Another easy way to get a Moat Carp Creel is to do Moblin Maze Mongers Maze Voucher 08 Aquatic Depopulation Team and pick Claraisse after you win.\n3. Trade the three items to the Green Thumb Moogle and he will say to come back in a day or so.\n4. Wait one game day and zone back into your Mog Garden.  A cutscene will start as you zone in.\n5. After the cutscene speak to your Green Thumb Moogle to complete the quest and receive your Hoe.',
        notes = 'After visiting your Mog Garden for 19 different Earth days, you will be cleared on the 20th day for this quest. Having 20 stars on your GPS crystal might not necessarily be enough as you can obtain extra stars during certain campaigns. You must still enter the Mog Garden on 20 separate Earth days. You can see how many days you\'ve visited the Mog Garden by speaking to your Green Thumb Moogle, asking to "Learn about the Mog Garden" and selecting "Tidbits of information."',
    },
    ['In Search of the Truth'] = {
        id = 80,
        start_npc = 'Tressia',
        start_zone = 'Tavnazian Safehold',
        start_pos = nil,
        description = 'Search for information regarding what happened on the day Wazozo\'s treasure was stolen.',
        reward = 'Gramary Cape',
        fame = 'Other',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Tressia (J-6, Third Floor: Patrol HQ)\n2. Optional - Speak to Mengrenaux (J-6, Third Floor: Patrol HQ)\n3. Optional - Speak to Chemioue (J-6, Third Floor: Patrol HQ)\n4. Speak to the following in any order to watch short cutscenes\n   - Fouagine (I-9, Third Floor: under archway)\n   - Noam (G-9, Second Floor: lower section)\n   - Zadant (H-8, Second Floor: on the ramp down to First Floor)\n   - Raminey (J-7 Third Floor: Home Point #3)\n5. Return to Tressia (J-6)\n   - You will be asked to put the information in chronological order\n     - (Fouagine, Zadant, Raminey, Noam) is one possible solution. Though should your order be incorrect, you may attempt the given order repeatedly until the solution is found.\n6. You will be asked to view the data gathered by the other members of the patrol and find out the  where the report was gathered\n   - Reports 1 and 2 - Speak to Mengrenaux (J-6)\n   - Reports 3 and 4 - Speak to Chemioue (J-6)\n7. Return to Tressia (J-6) and answer:\n   - Report 1:\n   - Report 2:\n   - Report 3:\n   - Report 4:\n8. Follow the trail\n   - Start by checking the ??? next to Noam (G-9, Second Floor) to receive Shaded Cruse\n   - Go north and up the ramp until you find another ??? (G-7)\n   - Continue upward and take the next left where there\'s another ??? near the open doors (G-8)\n   - Continue through the hallway and check the ??? at (H-8)\n   - Go left at the end of the hallway and check the ??? at the bottom right corner of (H-8)\n9. Return to Tressia (J-6, Third Floor: Patrol HQ)\n10. Go to Ondieulix (I-7, Second Floor: Near Home Point #1) for your reward',
        notes = '1. The suspicious traveler doesn\'t speak, but with /names on you can see he is Miledo-Shiraddo from Chameleon Capers',
    },
    ['In the Name of Science'] = {
