    ['Inside the Belly'] = {
        id = 26,
        start_npc = 'Zaldon',
        start_zone = 'Selbina',
        start_pos = 'H-9',
        description = 'Some fish in Vana\'diel like to eat shiny objects. If you catch one, let Zaldon cut it open for you.',
        reward = 'Gil, see the tables below.\nPotentially an item, see the tables below.',
        fame = 'Other',
        fame_level = nil,
        title = 'Multiple, see table below.',
        repeatable = 'Yes',
        previous = {'The Real Gift'},
        next = nil,
        requirements = {
            {name = 'Varies (see below)', count = 1},
        },
        walkthrough = '1. Have 30 fishing skill or greater, including temporary boosts from either gear or image support, and talk to Zaldon.\n   - The latent effect of Trainee\'s spectacles has also been confirmed to count toward the 30 skill requirement.\n   - Once you\'ve flagged the quest by talking to Zaldon with adequate fishing skill and The Real Gift completed, you will be able to complete the quest for the first time even if you\'re under 30, as well as for subsequent turn-ins.\n   - Zaldon will change his dialogue dynamically whether or not you have 30+ skill (telling you to talk to Gabwaleid if you have 29 or lower), but will still accept fish as long as you\'ve flagged the quest.\n2. Trade Zaldon certain fish and he will gut them for you.\n3. He will buy the fish that you trade for a fixed price, as well as give you anything that might be in its stomach.\n4. As of the November 10th, 2021 Version Update, the chance to receive an item is increased when a bigger fish is traded. Fish size is noted on each fish when looking at it in your inventory.\n5. Note: After completing the quest for the first time, you no longer need to meet the fishing level requirement to repeat the quest.\nSynthed into Dashing Subligar',
        notes = nil,
    },
    ['It\'s Raining Mannequins'] = {
        id = 29,
        start_npc = 'Fyi Chalmwoh',
        start_zone = 'Mhaura',
        start_pos = 'G-8',
        description = 'Fyi Chalmwoh wants to build a mannequin that rivals those of times past. It\'s your job to gather information on how to make one.',
        reward = 'One of the following based on your race:\nEF Mannequin \nEM Mannequin \nG Mannequin \nHF Mannequin \nHM Mannequin \nM Mannequin \nTM Mannequin \nTF Mannequin',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = nil,
        next = {'Behind the Smile'},
        requirements = {
            {name = 'Mannequin Body', count = 1},
            {name = 'Mannequin Feet', count = 1},
            {name = 'Mannequin Hands', count = 1},
            {name = 'Mannequin Head', count = 1},
            {name = 'Mannequin Legs', count = 1},
        },
        walkthrough = '1. Speak to Fyi Chalmwoh in Mhaura at (G-8) to begin the quest, then speak to her again.\n2. Speak to Ramona in Selbina at (H-9) to receive [Key Item] Ye Olde Mannequin Catalogue.\n3. Speak to Cheupirudaux in Northern San d\'Oria HP #4 at (F-3) to receive [Key Item] Mannequin joint diagrams.\n4. Gather all 5 Mannequin pieces and trade them to Fyi Chalmwoh. These can be also be bought off player\'s bazaars:\n   - Mannequin Body\n   - Mannequin Feet\n   - Mannequin Hands\n   - Mannequin Head\n   - Mannequin Legs\n5. Zone and speak to Fyi Chalmwoh again to receive your reward.',
        notes = nil,
    },
    ['Knocking on Forbidden Doors'] = {
        id = 78,
        start_npc = 'Enaremand',
        start_zone = 'Tavnazian Safehold',
        start_pos = nil,
        description = 'Enaremand\'s final masterpiece is complete, but not as complete as he would like. The troubled mannequin craftsman has now asked you to help him find a necromancer in order to breathe life into his creation...',
        reward = 'Ability to pose your mannequin.',
        fame = 'Other',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Behind the Smile'},
        next = nil,
        requirements = {
            {name = 'Mire incense', count = 1},
            {name = 'Better Humes and Mannequins', count = 1},
        },
        walkthrough = '1. Talk with Enaremand (J-7).\n2. Talk to Chemioue (J-6).\n   - If you haven\'t done Petals for Parelbriaux, and are at Promathia Mission 3-5 or later, you may get that cut-scene first.\n3. Go to Phomiuna Aqueducts, find a Wooden Ladder at C-9 on the second map, and climb the ladder for a cut-scene.\n4. Go to Misareaux Coast and select the ??? at I-6 near the end of the river for the [Key Item]Mire incense.\n5. Go to the base of the waterfall at F-4 in Misareaux Coast and select the ??? for a cut-scene.\n6. Select the ??? again to spawn the mannequin NM Alsha.\n   - The NM can cast Silence, Paralyze, and will occasionally cast Cure III on you.\n   - Once she is reduced to around 20%, and Alsha will repeatedly cast Fire II on herself until she dies.\n     - If she kills herself, you will have to rezone and try to kill her again; you must deal the final blow to defeat her.\n7. Once Alsha is defeated, select the ??? again to obtain [Key Item]Better Humes and Mannequins.\n8. Travel to Mhaura and talk to Fyi Chalmwoh who will take the key item then allow you to pose your mannequins for 200 Gil.',
        notes = nil,
    },
