    ['Picture Perfect'] = {
        id = 31,
        start_npc = 'Diederik',
        start_zone = 'Selbina',
        start_pos = 'G-10',
        description = 'Diederik has lost a painting ordered by a valued customer. He wants you to help him earn time or get a new painting before anyone notices.',
        reward = 'Raises Adventuring Fellow level cap to 55',
        fame = nil,
        fame_level = nil,
