    ['Survival of the Wisest'] = {
        id = 33,
        start_npc = 'Prof. Schultz',
        start_zone = 'Xarcabard',
        start_pos = nil,
        description = 'What will be the first and final assignment given to you by Gunther Schultz II, the legendary reformer of military strategy? Your rite of passage begins by obtaining a scholar\'s testimony...',
        reward = 'Raises level limit to 75.',
        fame = 'Other',
        fame_level = nil,
        title = 'Grimoire Bearer',
        repeatable = nil,
        previous = {'Seeing Blood-red'},
        next = {'New Worlds Await'},
        requirements = {
            {name = 'Scholar\'s Testimony', count = 1},
        },
        walkthrough = '1. Zone into Xarcabard to get a cutscene (Teleport-Vahzl works as well).\n   - You must wait until the next game day after completing the prior quest before this event triggers.\n2. Obtain a Scholar Testimony, dropped by Orcish Stonechuckers in East Ronfaure (S).\n   - Other orcs of same lv may also drop the Testimony.\n3. Travel to the Throne Room to get a cutscene at the door, then trade the testimony to start the fight. All buffs are lost upon entering, as well as subjobs.\n   - If you have the "Rhapsody in Umber" Key Item, you are able to summon Trust Magic to aid you.\n4. There are 2 enemies to fight, Schultz and his Crimson Grimoire, both unsleepable or very difficult to sleep. It is recommended to start quickly as both of them will be buffed if too much time is wasted. The Grimoire has much less HP, and is recommended to be killed first as it will not cast often and instead come to you and melee. It should be noted that it did attempt to cast Pyrohelix, although strangely enough Water IV only healed it\'s HP. Thunder 4 took down more then half of it\'s life.\n5. Schultz will give up at around 20% or so. The Grimoire does not have to be killed to win.',
        notes = '1. Does not need to be completed (for level limit increasing) if the player has already completed New Worlds Await or better.',
    },
    ['Tango with a Tracker'] = {
        id = 82,
        start_npc = 'Despachiaire',
        start_zone = 'Tavnazian Safehold',
        start_pos = 'K-10',
        description = 'A letter from Shikaree X addressed to you has arrived in the safehold. It appears she wants to gauge your battle prowess in Boneyard Gully.',
        reward = '10,000 gil',
        fame = 'Other',
        fame_level = nil,
        title = 'Sin Hunter Hunter',
        repeatable = nil,
        previous = nil,
        next = {'Requiem of Sin'},
        requirements = nil,
        walkthrough = '1. Speak to Despachiaire to obtain Letter from Shikaree X.\n2. Head to Boneyard Gully and select "" at the Dark Miasma to enter a battlefield.\n3. You have 30 minutes to complete this quest.  You are also allowed 6 party members to help you with the fight.\n   - Trusts are not allowed in the fight arena.\n4. This fight is against:\n   - Shikaree X: BST/NIN\n   - Shikaree X\'s Rabbit: Resistant to sleep but not bind and gravity.\n     - If it is killed before Shikaree X, another one will be summoned in it\'s place.\n   - Shikaree Y: DRK/MNK\n5. The Shikaree\'s are both difficult to sleep and the effect will not last long on either of them.\n6. They gain TP very quickly and will attempt to Skillchain with each other.\n7. Once all three are defeated, the fight will end and you will receive your reward.',
        notes = nil,
    },
    ['Test My Mettle'] = {
        id = 25,
        start_npc = 'Devean',
        start_zone = 'Selbina',
        start_pos = 'I-8',
        description = 'Find the pair of power sandals hidden in a jar somewhere in Davoi. Bring them back before time runs out for a cash prize.',
        reward = nil,
        fame = 'Other',
        fame_level = nil,
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Devean who will ask you to bet on how long it takes you to get a pair of Power Sandals from Davoi.\n   - The quicker you return, the more money you get back.\n   - The time is measured in game hours, not earth hours.\n2. Once in Davoi you need to locate a Jar that contains the Power Sandals.\n   - The jar can spawn at (I-8), (K-9), (J-8), (H-8), (F-6), (J-9), (F-9), (G-9), (H-9), and (F-7).\n3. Return the Power Sandals to Devean before time runs out.\n4. You can also choose to keep the Power Sandals for yourself.  This however means that you will fail the quest.',
        notes = nil,
    },
    ['The Basics'] = {
        id = 6,
        start_npc = 'Rycharde',
        start_zone = 'Mhaura',
        start_pos = 'H-8',
        description = 'Rycharde wants you to deliver a dish to Valgeir in Selbina, and report on how he liked it.',
        reward = 'Tea Set',
