    ['Titillating Tomes'] = {
        id = 200,
        start_npc = 'Green Thumb Moogle',
        start_zone = 'Mog Garden',
        start_pos = nil,
        description = 'The Great Kupellion has come to your Mog Garden to help cure the MHMU scholars\' wibbly wobbly woozies.  He will need drill calamary from the beach, a calico comet from the pond, and a philosopher\'s stone from a mineral vein.',
        reward = 'Straw Hat',
        fame = 'Other',
        fame_level = nil,
        title = 'Wibbly Wobbly Woozy Warrior',
        repeatable = nil,
        previous = {'Hypnotic Hospitality'},
        next = {'Glittering Gals'},
        requirements = {
            {name = 'Drill Calamary', count = 1},
            {name = 'Calico Comet', count = 1},
            {name = 'Philosopher\'s Stone', count = 1},
        },
        walkthrough = '1. Once you have achieved rank 7 in all geological locations (that is, you have bought the MHMU treatises for all sections of your Mog Garden except monster rearing), zone into your Mog Garden and talk to your Green Thumb Moogle.\n2. He will ask for the following items.\n   - Drill Calamary can be obtained from the Coastal Fishing Net or commonly through the Repeat Login Campaign.\n   - Calico Comet can be obtained from the Pond Dredger or purchased on the Auction House under the category Fish.\n   - Philosopher\'s Stone can be obtained from the Mineral Vein or purchased on the Auction House under the category Alchemy.\n3. Trade all the items at once to the Moogle in order to complete the quest.',
        notes = nil,
    },
    ['Trial by Lightning'] = {
        id = 27,
        start_npc = 'Ripapa',
        start_zone = 'Mhaura',
        start_pos = 'I-9',
        description = 'Ring the tuning fork of lightning upon the protocrystal in the The Boyahda Tree',
        reward = 'Ramuh (Avatar)\n10,000 Gil\nRamuh\'s Staff\nLightning Belt\nLightning Ring\nElder Branch',
        fame = 'Other',
        fame_level = nil,
        title = 'Heir of the Great Lightning',
        repeatable = 'Yes',
        previous = nil,
        next = {
            'The Moonlit Path',
            'Mama Mia',
        },
        requirements = nil,
        walkthrough = '1. Speak with Ripapa to obtain the quest. If you are positive that you have the required fame but she is not allowing you to undertake this quest, continue speaking with her until her text changes. Once you have received the key item: Tuning fork of lightning, you can now safely undertake the quest.\n2. Travel to The Sanctuary of Zi\'Tah enter to The Boyahda Tree at (K-12) or (J-12). On the first map of The Boyahda Tree, travel to (A-7) to climb to the second map. On the second map, go behind the waterfall at (I-11) to find the hidden entrance to the Cloister of Storms.\n   - Preferably, home point to The Boyahda Tree #1. If you don\'t have it yet, make sure to grab it on the way.\n   - The Unity 135 warp will put you on map B so the home point is a short run away. Beware of aggro from mobs even at level 99.\n3. Defeat Ramuh Prime and you will receive a key item: Whisper of storms\n4. Return to Ripapa with the whisper and she will provide several reward options including the ability to summon Ramuh.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own Tuning fork of lightning.\n3. Time limit is 30 minutes.\n4. You can only select one of the rewards Ripapa offers at any time.\n5. You may repeat this quest once per Earth day.\n6. You can save yourself a lot of time traveling to the Cloister by using the Mini Fork of Ltn. given by the quest Trial-Size Trial by Lightning.  You must be on Summoner as your main job, and obtain the Mini Tuning Fork from Lacia, trade the fork back to Lacia, but enter the Protocrystal normally.  So long as you do not clear the level 20 version of the BC, you may warp to the Cloister as many times as you wish.\n7. You may also choose to retain the whisper in order to complete the requirements for this quest: The Moonlit Path.',
    },
    ['Trial of the Chacharoon'] = {
        id = 205,
        start_npc = 'Susuroon',
        start_zone = 'Mog Garden',
        start_pos = nil,
        description = 'Chacharoon\'s life savings have been pilfered by some uncouth savage, and Susuroon can\'t face the young one himself. Head toward the newly cultivated area via the path located near the boat to find him.',
        reward = 'Trust Magic: Chacharoon',
        fame = 'Other',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Chacharoon\'s Cheer'},
        next = {'Doctor Chacharoon'},
        requirements = nil,
        walkthrough = '1. Care for monsters an additional 5 times in order to purchase "Sakura and the Fountain" from Zenicca or a Skipper Moogle.\n2. After purchasing the key item, enter your newly expanded Mog Garden area which features the Rearing Grounds.\n   - While these are not directly rewarded by this quest and can be obtained while earlier quests in this line are still active, this key item allows for the following:\n     - Access to the Rearing Grounds\n     - Ability to raise two monsters at once\n3. Speak to Chacharoon in the newly open area to complete the quest and gain access to use the Trust Magic: Chacharoon.',
        notes = nil,
    },
    ['Trial-Size Trial by Lightning'] = {
        id = 28,
        start_npc = 'Lacia',
        start_zone = 'Mhaura',
        start_pos = 'I-9',
        description = 'The Rhinostery has developed a new "mini" tuning fork of lightning. Ringing it upon the protocrystal in the Boyahda Tree will open the path to a one-on-one battle with the beast that awaits inside. However, only summoners are allowed to take up this challenge.',
        reward = 'Scroll of Instant Warp\nRamuh (Avatar)',
        fame = 'Other',
        fame_level = '2',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak with Lacia in Mhaura (I-9) to begin quest and obtain a Mini Tuning Fork of Lightning.\n2. You may prepare for the upcoming battle and whenever you are ready, trade Lacia the tuning fork to be transported to the arena.\n3. Trade the fork to the Lightning Protocrystal to enter the fighting arena.\n4. Defeat Ramuh Prime to complete quest.',
        notes = '1. Only Carbuncle may be used for this battle.\n   - Siren can also be used but it seems unintended.\n2. Use pet food (e.g. Grape Daifuku) and bring along a few Dawn Mulsum and juices if you don\'t want to use Astral Flow\n3. You must face this challenge alone.\n4. You may buff outside of the fight. Level cap will not dispel them.\n5. There is a 15 minutes time limit on the arena.\n6. Warning You may re-obtain the Mini Tuning Fork from the starting NPC at any point if you desire and repeat the fight, but the NPC will no longer teleport you to the Cloister.\n   - These were historically prized for their teleportation abilities, but Home Point warps have largely supplanted them.',
    },
